mapper.select:
SELECT * FROM ( SELECT SUBSTRING(tpm.receipt_dt, 1, 8) AS receipt, SUBSTRING(tpm.receipt_dt, 5, 2) AS receipt_month, SUBSTRING(tpm.receipt_dt, 1, 6) AS receipt_month_group, -- yyyyMM 단위 tpm.ppe_id, tdp.ppe_nm,
-- 해당 월의 가장 최신 receipt_dt MAX(tpm.receipt_dt) OVER (PARTITION BY tpm.ppe_id, SUBSTRING(tpm.receipt_dt, 1, 6)) AS receipt_dt,
( SELECT store_qty FROM esg.tb_ppe_manage WHERE comp_id = #{compId} AND ppe_id = tpm.ppe_id ORDER BY write_year DESC, doc_no DESC LIMIT 1 ) AS store_qty,
( SELECT MAX(receipt_dt) FROM esg.tb_ppe_manage WHERE comp_id = #{compId} AND ppe_id = tpm.ppe_id ) AS last_receipt_dt,
COUNT(*) OVER (PARTITION BY tpm.ppe_id, SUBSTRING(tpm.receipt_dt, 1, 6)) AS receipt_cnt, -- 월별 건수 ROW_NUMBER() OVER (PARTITION BY tpm.ppe_id, SUBSTRING(tpm.receipt_dt, 1, 6) ORDER BY tpm.receipt_dt DESC) AS rn, -- 최신순으로 추출
#{writeYear} AS write_year, tdp.use_yn FROM esg.tb_ppe_manage tpm JOIN esg.tb_ppe_items tdp ON tpm.ppe_id = tdp.ppe_id AND tpm.comp_id = tdp.comp_id WHERE tpm.comp_id = #{compId}
AND tpm.write_year = #{writeYear}
AND tpm.receipt_dt = #{docDetailSeq}
AND tpm.ppe_id = #{docSeq}
) sub WHERE rn = 1 ORDER BY use_yn desc, receipt_month_group desc, ppe_id

mapper.delete:
