		 WHERE write_year = #{writeYear}
		   AND doc_type = #{docType}
		   AND doc_no = #{docNo}

mapper.select:
SELECT tdp.*, (SELECT MAX(receipt_dt) FROM esg.tb_ppe_manage WHERE comp_id = #{compId} AND ppe_id = tdp.ppe_id) AS last_receipt_dt, (SELECT store_qty FROM esg.tb_ppe_manage WHERE comp_id = #{compId} AND ppe_id = tdp.ppe_id ORDER BY write_year DESC, doc_no DESC LIMIT 1) AS store_qty FROM esg.tb_ppe_items tdp WHERE comp_id = #{compId} AND use_yn = 'Y' AND ppe_id IN
#{ppeId}
ORDER BY ord_seq

mapper.update:
UPDATE esg.tb_ppe_items
   SET ppe_nm = #{ppeNm}
     , provision_standard = #{provisionStandard}	
	 , provision_target= #{provisionTarget}	
	 , use_yn = #{useYn}	
	 , ord_seq = #{ordSeq}
	 , updated_at = now()
	 , updated_by = #{createdBy}	
 WHERE comp_id = #{compId}
   AND ppe_id = #{ppeId}

mapper.delete:
    	update esg.tb_ppe_items
    	   set use_yn = 'N'
			 , updated_at = now()
			 , updated_by = #{createdBy}
		 WHERE comp_id = #{compId}
		   AND ppe_id = #{ppeId}
